const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let res=[];
for(let t=0;t<T;t++){
  const n=Number(input[idx++]);
  const k=Number(input[idx++]);
  const arr=new Array(n);
  for(let i=0;i<n;i++) arr[i]=Number(input[idx++]);
  let cur=0;
  for(let i=0;i<k;i++) cur+=arr[i];
  let best=cur;
  for(let i=k;i<n;i++){
    cur+=arr[i]-arr[i-k];
    if(cur>best) best=cur;
  }
  res.push(String(best));
}
console.log(res.join('\n'));
